#include<iostream>#include<vector>#include<algorithm>#include<climits>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        ll sum=0;        ll neg_cnt=0;        vector<int>a(n);        for(int i=0;i<n;i++){            cin>>a[i];            if(a[i]<0){                neg_cnt++;                a[i] = -a[i];            }            sum+=a[i];        }        if(neg_cnt%2==0){            cout<<sum<<"\n";        }        else{            sort(a.begin(),a.end());            cout<<sum - (2 * a[0])<<"\n";        }    }}